1	import {
2	  clipPolygon,
3	  ensureCW,
4	  faceToPath,
5	  polyBounds,
6	  project,
7	  signedArea,
8	} from "./math";
9	import type { Bounds, Box3D, Face, Polygon, Shape } from "./types";
10	
11	// ── Face constructors ────────────────────────────────────
12	
13	function topFace(b: Box3D): Face {
14	  const z = b.z + b.d;
15	  return {
16	    contour: ensureCW([
17	      project(b.x, b.y, z),
18	      project(b.x + b.w, b.y, z),
19	      project(b.x + b.w, b.y + b.h, z),
20	      project(b.x, b.y + b.h, z),
21	    ]),
22	    holes: [],
23	    type: "top",
24	  };
25	}
26	
27	function frontFace(b: Box3D): Face {
28	  // y=h plane (the "back" in 3D, but faces the viewer in iso projection)
29	  return {
30	    contour: ensureCW([
31	      project(b.x, b.y + b.h, b.z),
32	      project(b.x + b.w, b.y + b.h, b.z),
33	      project(b.x + b.w, b.y + b.h, b.z + b.d),
34	      project(b.x, b.y + b.h, b.z + b.d),
35	    ]),
36	    holes: [],
37	    type: "front",
38	  };
39	}
40	
41	function rightFace(b: Box3D): Face {
42	  return {
43	    contour: ensureCW([
44	      project(b.x + b.w, b.y, b.z),
45	      project(b.x + b.w, b.y + b.h, b.z),
46	      project(b.x + b.w, b.y + b.h, b.z + b.d),
47	      project(b.x + b.w, b.y, b.z + b.d),
48	    ]),
49	    holes: [],
50	    type: "right",
51	  };
52	}
53	
54	// ── Silhouette (hexagonal outline of isometric box) ──────
55	
56	function silhouette(b: Box3D): Polygon {
57	  return ensureCW([
58	    project(b.x, b.y, b.z + b.d),
59	    project(b.x + b.w, b.y, b.z + b.d),
60	    project(b.x + b.w, b.y, b.z),
61	    project(b.x + b.w, b.y + b.h, b.z),
62	    project(b.x, b.y + b.h, b.z),
63	    project(b.x, b.y + b.h, b.z + b.d),
64	  ]);
65	}
66	
67	// ── AABB intersection ────────────────────────────────────
68	
69	function aabbHit(a: Box3D, b: Box3D): Box3D | null {
70	  const x = Math.max(a.x, b.x);
71	  const y = Math.max(a.y, b.y);
72	  const z = Math.max(a.z, b.z);
73	  const mx = Math.min(a.x + a.w, b.x + b.w);
74	  const my = Math.min(a.y + a.h, b.y + b.h);
75	  const mz = Math.min(a.z + a.d, b.z + b.d);
76	  if (mx <= x || my <= y || mz <= z) {
77	    return null;
78	  }
79	  return { x, y, z, w: mx - x, h: my - y, d: mz - z };
80	}
81	
82	// ── Inner faces revealed by subtraction ──────────────────
83	// When B is subtracted from A, the cavity exposes three inner
84	// surfaces (the ones whose outward normals face the viewer):
85	//   bottom floor  (z = int.z,      normal +z → renders like "top")
86	//   back wall     (y = int.y+int.h, normal -y → renders like "front")
87	//   left wall     (x = int.x,      normal +x → renders like "right")
88	
89	function innerFaces(a: Box3D, b: Box3D): Face[] {
90	  const int = aabbHit(a, b);
91	  if (!int) {
92	    return [];
93	  }
94	  const out: Face[] = [];
95	
96	  // Bottom floor — only if cavity does not punch through A's bottom
97	  if (int.z > a.z) {
98	    const c = ensureCW([
99	      project(int.x, int.y, int.z),
100	      project(int.x + int.w, int.y, int.z),
101	      project(int.x + int.w, int.y + int.h, int.z),
102	      project(int.x, int.y + int.h, int.z),
103	    ]);
104	    if (c.length >= 3 && Math.abs(signedArea(c)) > 0.01) {
105	      out.push({ contour: c, holes: [], type: "top" });
106	    }
107	  }
108	
109	  // Front wall — only if cavity does not punch through A's front
110	  if (int.y > a.y) {
111	    const c = ensureCW([
112	      project(int.x, int.y, int.z),
113	      project(int.x + int.w, int.y, int.z),
114	      project(int.x + int.w, int.y, int.z + int.d),
115	      project(int.x, int.y, int.z + int.d),
116	    ]);
117	    if (c.length >= 3 && Math.abs(signedArea(c)) > 0.01) {
118	      out.push({ contour: c, holes: [], type: "front" });
119	    }
120	  }
121	
122	  // Left wall — only if cavity does not punch through A's left
123	  if (int.x > a.x) {
124	    const c = ensureCW([
125	      project(int.x, int.y, int.z),
126	      project(int.x, int.y + int.h, int.z),
127	      project(int.x, int.y + int.h, int.z + int.d),
128	      project(int.x, int.y, int.z + int.d),
129	    ]);
130	    if (c.length >= 3 && Math.abs(signedArea(c)) > 0.01) {
131	      out.push({ contour: c, holes: [], type: "right" });
132	    }
133	  }
134	
135	  return out;
136	}
137	
138	// ── Clip a face, adding a hole where it overlaps `sil` ───
139	
140	function clipFace(face: Face, sil: Polygon): Face {
141	  const hole = clipPolygon(face.contour, sil);
142	  if (hole.length < 3 || Math.abs(signedArea(hole)) < 0.01) {
143	    return face;
144	  }
145	  return { ...face, holes: [...face.holes, hole] };
146	}
147	
148	// ── Public API ───────────────────────────────────────────
149	
150	/** Create a shape from a single box */
151	export function createBox(b: Box3D): Shape {
152	  // Render order: right (deepest) → front → top (closest)
153	  return { faces: [rightFace(b), frontFace(b), topFace(b)] };
154	}
155	
156	/** A minus B — carves B out of A */
157	function _subtract(a: Box3D, b: Box3D): Shape {
158	  if (!aabbHit(a, b)) {
159	    return createBox(a);
160	  }
161	
162	  const bSil = silhouette(b);
163	  const outer = createBox(a).faces.map((f) => clipFace(f, bSil));
164	  const inner = innerFaces(a, b);
165	
166	  // Inner faces first (behind), then outer faces with holes (in front)
167	  return { faces: [...inner, ...outer] };
168	}
169	
170	/** A ∪ B — combined volume of both boxes */
171	function _union(a: Box3D, b: Box3D): Shape {
172	  if (!aabbHit(a, b)) {
173	    return { faces: [...createBox(a).faces, ...createBox(b).faces] };
174	  }
175	
176	  const aSil = silhouette(a);
177	  const aFaces = createBox(a).faces;
178	  const bFaces = createBox(b).faces.map((f) => clipFace(f, aSil));
179	
180	  // A's full faces, then B's faces with A's overlap removed
181	  return { faces: [...bFaces, ...aFaces] };
182	}
183	
184	/** A ∩ B — only the overlapping volume */
185	function _intersect(a: Box3D, b: Box3D): Shape {
186	  const int = aabbHit(a, b);
187	  if (!int) {
188	    return { faces: [] };
189	  }
190	  return createBox(int);
191	}
192	
193	// ── Render helpers ───────────────────────────────────────
